# ─── Login Gate ───────────────────────────────────────────────────────────────
def _check_login():
    """Simple password gate. Set DASHBOARD_PASSWORD in st.secrets or env."""
    import os as _os_login
    _pw = st.secrets.get("DASHBOARD_PASSWORD", None) if hasattr(st, "secrets") else None
    if _pw is None:
        _pw = _os_login.environ.get("DASHBOARD_PASSWORD", "SharpenTheEdge2025")

    if st.session_state.get("_authenticated"):
        return True

    # ── Login screen ──
    st.markdown("""
    <style>
      .login-wrap {
        max-width: 420px; margin: 80px auto 0; padding: 40px 36px 32px;
        background: #ffffff; border-radius: 12px;
        box-shadow: 0 4px 24px rgba(0,0,0,0.10);
        border-top: 4px solid #8B1A1A;
      }
      .login-title { color:#8B1A1A; font-size:1.35rem; font-weight:700;
                     letter-spacing:.04em; text-transform:uppercase; margin-bottom:4px; }
      .login-sub   { color:#555; font-size:0.85rem; margin-bottom:24px; }
    </style>
    <div class='login-wrap'>
      <p class='login-title'>🍺 Beer Pricing Dashboard</p>
      <p class='login-sub'>Southern Crown Partners · Sharpen the Edge</p>
    </div>
    """, unsafe_allow_html=True)

    with st.form("login_form"):
        st.markdown("#### Sign In")
        entered = st.text_input("Password", type="password", placeholder="Enter password")
        submitted = st.form_submit_button("Sign In", use_container_width=True)

    if submitted:
        if entered == _pw:
            st.session_state["_authenticated"] = True
            st.rerun()
        else:
            st.error("Incorrect password. Please try again.")

    st.stop()
    return False

_check_login()


